class OAuthRedirectActivity : AppCompatActivity() {

    class Callback(private val onResult: (OAuthRedirectResult) -> Unit) {
        fun dispatch(result: OAuthRedirectResult) = onResult(result)
    }

    companion object {
        @Volatile
        private var callback: Callback? = null

        fun setCallback(cb: Callback) {
            callback = cb
        }
    }

    override fun onResume() {
        super.onResume()
        try {
            val data = intent?.data
            if (data == null) {
                callback?.dispatch(OAuthRedirectResult.Cancelled)
                finish()
                return
            }

            val code = data.getQueryParameter("code")
            val state = data.getQueryParameter("state")
            val error = data.getQueryParameter("error")

            if (!error.isNullOrBlank()) {
                callback?.dispatch(OAuthRedirectResult.Error(SocialLoginException(error)))
            } else {
                callback?.dispatch(OAuthRedirectResult.Success(code, state))
            }
        } catch (t: Throwable) {
            callback?.dispatch(OAuthRedirectResult.Error(t))
        } finally {
            finish()
        }
    }
}

object HttpClient {
    private val client = okhttp3.OkHttpClient.Builder().build()

    suspend fun getJson(url: String): JSONObject = withContext(Dispatchers.IO) {
        val request = okhttp3.Request.Builder().url(url).get().build()
        client.newCall(request).execute().use { response ->
            val body = response.body?.string() ?: throw SocialLoginException("Empty response")
            if (!response.isSuccessful) throw SocialLoginException("HTTP ${response.code}: $body")
            JSONObject(body)
        }
    }

    suspend fun getJsonWithBearer(url: String, bearerToken: String): JSONObject = withContext(Dispatchers.IO) {
        val request = okhttp3.Request.Builder()
            .url(url)
            .get()
            .addHeader("Authorization", "Bearer $bearerToken")
            .build()
        client.newCall(request).execute().use { response ->
            val body = response.body?.string() ?: throw SocialLoginException("Empty response")
            if (!response.isSuccessful) throw SocialLoginException("HTTP ${response.code}: $body")
            JSONObject(body)
        }
    }

    suspend fun postFormJson(url: String, formBody: String): JSONObject = withContext(Dispatchers.IO) {
        val mediaType = okhttp3.MediaType.parse("application/x-www-form-urlencoded; charset=utf-8")
            ?: throw SocialLoginException("Invalid media type")
        val requestBody = okhttp3.RequestBody.create(mediaType, formBody)
        val request = okhttp3.Request.Builder().url(url).post(requestBody).build()
        client.newCall(request).execute().use { response ->
            val body = response.body?.string() ?: throw SocialLoginException("Empty response")
            if (!response.isSuccessful) throw SocialLoginException("HTTP ${response.code}: $body")
            JSONObject(body)
        }
    }
}

